appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    // Safely extract all data sources
    const apkData = model.apk_data || {};
    const cookies = Array.isArray(model.cookies) ? model.cookies : [];
    const policyRules = model.governance_policy?.entity_rules || {};
    let driftData = [];

    // --- 1. Network & Entity Drift Analysis ---
    const observedNetworks = new Set();

    // Gather domains from cookies
    cookies.forEach(c => {
      if (c.domain) observedNetworks.add(c.domain.toLowerCase());
    });

    // Gather networks from APK trackers
    if (Array.isArray(apkData.trackers)) {
      apkData.trackers.forEach(t => {
        if (t.network) observedNetworks.add(t.network.toLowerCase());
        if (t.url) observedNetworks.add(t.url.toLowerCase());
      });
    }

    // Heuristic flags to check specific entities
    let googleObserved = false;
    let facebookObserved = false;
    observedNetworks.forEach(net => {
      if (net.includes('google')) googleObserved = true;
      if (net.includes('facebook') || net.includes('graph.')) facebookObserved = true;
    });

    // Evaluate Google against Governance Policy
    if (googleObserved) {
      const googlePolicy = policyRules["Google LLC"];
      if (googlePolicy) {
        driftData.push({
          element: "Google LLC Data Flow",
          declared: `Authorized for: ${googlePolicy.authorized_role}`,
          observed: "Observed execution aligns with Analytics & Performance limits.",
          status: "Safe"
        });
      } else {
        driftData.push({
          element: "Google LLC Data Flow",
          declared: "Not declared in Governance Policy",
          observed: "Active egress to Google domains observed.",
          status: "Warning"
        });
      }
    }

    // Evaluate Facebook against Governance Policy
    if (facebookObserved) {
      const fbPolicy = policyRules["Facebook"] || policyRules["Meta"];
      if (!fbPolicy) {
        driftData.push({
          element: "Facebook / Meta Graph",
          declared: "Not declared in Governance Policy",
          observed: "Egress to Third-Party Graph (graph.facebook.com) detected in payload.",
          status: "Critical"
        });
      }
    }

    // --- 2. AI Model & Logic Drift Analysis ---
    // Dynamically check if ML logic exists in the APK natively
    const nativeCode = apkData?.android_api?.api_native_code?.files || {};
    let mlObserved = false;
    Object.keys(nativeCode).forEach(path => {
      if (path.includes("tensorflow") || path.includes("mlmodel") || path.includes("opencv")) mlObserved = true;
    });
    if (mlObserved) {
      driftData.push({
        element: "Embedded AI Components",
        declared: "No explicit AI logic authorized in baseline policy",
        observed: "Local ML / Neural models (e.g., TensorFlow Lite) initialized in codebase.",
        status: "Critical"
      });
    }

    // --- 3. PII & Eligibility Drift Analysis ---
    // Dynamically check if trackers are flagged as sensitive
    let sensitiveExposure = false;
    if (Array.isArray(apkData.trackers)) {
      sensitiveExposure = apkData.trackers.some(t => t.is_sensitive);
    }
    if (sensitiveExposure) {
      driftData.push({
        element: "Sensitive User Identifiers",
        declared: "Restricted to First-Party isolation",
        observed: "Identifiers flagged as highly eligible for external ingestion / egress.",
        status: "Warning"
      });
    }

    // --- Populate the UI ---

    // 1. Update Drift Summary
    const summaryElement = document.getElementById('drift-summary-text');
    const criticalDrifts = driftData.filter(d => d.status === 'Critical').length;
    if (criticalDrifts > 0) {
      summaryElement.innerHTML = `Zendata has detected <strong>${criticalDrifts} critical policy drift(s)</strong>. There is a meaningful gap between declared AI/data governance policies and the observed runtime behavior, primarily involving unsanctioned model execution or unauthorized third-party data egress.`;
      document.querySelector('.drift-summary').style.borderLeftColor = "#e67e22";
    } else {
      summaryElement.innerHTML = "Observed application behavior strictly aligns with declared AI/Data governance policies. No critical exposure drift detected.";
      document.querySelector('.drift-summary').style.borderLeftColor = "#27ae60"; // Make it green if safe
    }

    // 2. Populate Mismatch Table
    const tbody = document.getElementById('drift-table-body');
    tbody.innerHTML = '';
    if (driftData.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No policy drift detected.</td></tr>';
      return;
    }
    driftData.forEach(item => {
      const tr = document.createElement('tr');

      // Element
      const tdElement = document.createElement('td');
      tdElement.innerHTML = `<strong>${item.element}</strong>`;

      // Declared
      const tdDeclared = document.createElement('td');
      tdDeclared.textContent = item.declared;

      // Observed
      const tdObserved = document.createElement('td');
      tdObserved.textContent = item.observed;

      // Status Badge
      const tdStatus = document.createElement('td');
      const statusBadge = document.createElement('span');
      if (item.status === 'Critical') statusBadge.className = 'badge badge-critical';else if (item.status === 'Warning') statusBadge.className = 'badge badge-warning';else statusBadge.className = 'badge badge-safe';
      statusBadge.textContent = item.status + " Drift";
      tdStatus.appendChild(statusBadge);
      tr.appendChild(tdElement);
      tr.appendChild(tdDeclared);
      tr.appendChild(tdObserved);
      tr.appendChild(tdStatus);
      tbody.appendChild(tr);
    });
  });
});

